const builtins = require('builtin-modules');
const {
    MAIN_BUNDLE_OUTPUT_FILE,
    RENDER_HOST_RUNTIME_OUTPUT_FILE
} = require('./packaging-contract.js');

const BUNDLE_BANNER =
`/*
THIS IS A GENERATED/BUNDLED FILE BY ESBUILD
if you want to view the source, please visit the github repository of this plugin
*/
`;

const SHARED_EXTERNAL = [
    'obsidian',
    'electron',
    '@codemirror/autocomplete',
    '@codemirror/collab',
    '@codemirror/commands',
    '@codemirror/language',
    '@codemirror/lint',
    '@codemirror/search',
    '@codemirror/state',
    '@codemirror/view',
    '@lezer/common',
    '@lezer/highlight',
    '@lezer/lr',
    ...builtins
];

function resolveSourceMap(prod) {
    return prod ? false : 'inline';
}

function createMainBundleBuildOptions({
    prod = false,
    metafile = false,
    write = true,
    logLevel = 'info'
} = {}) {
    return {
        banner: {
            js: BUNDLE_BANNER
        },
        entryPoints: ['src/main.ts'],
        bundle: true,
        external: SHARED_EXTERNAL,
        loader: { '.txt': 'text' },
        format: 'cjs',
        target: 'es2018',
        logLevel,
        sourcemap: resolveSourceMap(prod),
        treeShaking: true,
        outfile: MAIN_BUNDLE_OUTPUT_FILE,
        minify: prod,
        metafile,
        write
    };
}

function createRenderHostBundleBuildOptions({
    prod = false,
    metafile = false,
    write = true,
    logLevel = 'info'
} = {}) {
    return {
        banner: {
            js: BUNDLE_BANNER
        },
        entryPoints: ['src/rendering/runtime/renderHostEntry.ts'],
        bundle: true,
        format: 'esm',
        target: 'es2020',
        logLevel,
        sourcemap: resolveSourceMap(prod),
        treeShaking: true,
        outfile: RENDER_HOST_RUNTIME_OUTPUT_FILE,
        minify: prod,
        platform: 'browser',
        metafile,
        write
    };
}

module.exports = {
    BUNDLE_BANNER,
    SHARED_EXTERNAL,
    createMainBundleBuildOptions,
    createRenderHostBundleBuildOptions
};
